public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;

    protected BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual IQueryable<T> GetAll()
    {
        return _context.Set<T>().AsNoTracking();
    }

    public virtual T GetById(object id)
    {
        return _context.Set<T>().Find(id);
    }

    public virtual T GetByDynamicField(string fieldName, object value)
    {
        return _context.Set<T>().AsNoTracking().FirstOrDefault(e => GetMemberValue(e, fieldName) == value);
    }

    private object GetMemberValue(object entity, string fieldName)
    {
        var propertyInfo = entity.GetType().GetProperty(fieldName);
        if (propertyInfo != null)
        {
            return propertyInfo.GetValue(entity);
        }
        else
        {
            var fieldInfo = entity.GetType().GetField(fieldName);
            if (fieldInfo != null)
            {
                return fieldInfo.GetValue(entity);
            }
        }
        return null;
    }
}
